module asyn_fifo
#(
    parameter WIDTH = 8,
    parameter DEPTH = 16
)
(
    input wclk,
    input rclk,
    input wrstn,
    input rrstn,
    input winc,
    input rinc,
    input [WIDTH-1:0] wdata:
);

    wire wenc, ren;
    wire [3:0] waddr, raddr;
    wire [WIDTH-1:0] wdata, rdata;
    wire [WIDTH-1:0] rdata_wire;
    wire [3:0] raddr_wire;

    dual_port_RAM dual_port_RAM_inst(
        .wclk(wclk),
        .wenc(wenc),
        .waddr(waddr),
        .wdata(wdata),
        .rclk(rclk),
        .ren(ren),
        .raddr(raddr),
        .rdata(rdata_wire)
    );

    reg [4:0] wptr, rptr;
    reg [4:0] waddr_bin, raddr_bin;
    reg [4:0] wptr_buff, rptr_buff;
    wire [4:0] wptr_syn, rptr_syn;

    always @(posedge wclk or negedge rst_n) begin
        if (!rst_n)
            wptr <= 5'd0;
        else if (winc) begin
            if (wptr == 5'b11111)
                wptr <= 5'd0;
            else
                wptr <= wptr + 1;
        end
    end

    always @(posedge wclk or negedge rst_n) begin
        if (!rst_n)
            waddr_bin <= 5'd0;
        else begin
            waddr_bin <= waddr_bin + winc;
        end
    end
    assign wptr_syn = {waddr_bin[4:3] ^ waddr_bin[3:2], waddr_bin[1:0] ^ waddr_bin[2:1]};

    always @(posedge rclk or negedge rrstn) begin
        if (!rrstn)
            rptr <= 5'd0;
        else if (rinc) begin
            if (rptr == 5'b11111)
                rptr <= 5'd0;
            else
                rptr <= rptr + 1;
        end
    end

    always @(posedge rclk or negedge rrstn) begin
        if (!rrstn)
            raddr_bin <= 5'd0;
        else begin
            raddr_bin <= raddr_bin + rinc;
        end
    end
    assign rptr_syn = {raddr_bin[4:3] ^ raddr_bin[3:2], raddr_bin[1:0] ^ raddr_bin[2:1]};

    assign wfull = (wptr[4:0] == ~rptr[4:0] && wptr[3:0] == rptr[3:0]);
    assign rempty = (rptr[4:0] == wptr[4:0]);

    always @(posedge wclk or negedge rst_n) begin
        if (!rst_n)
            wptr_buff <= 5'd0;
        else
            wptr_buff <= wptr;
    end
    always @(posedge rclk or negedge rrstn) begin
        if (!rrstn)
            rptr_buff <= 5'd0;
        else
            rptr_buff <= rptr;
    end

    assign ren = (rptr_syn[4:0] != wptr_buff[4:0]) && !rempty;
    assign wenc = (wptr_syn[4:0] != rptr_buff[4:0]) && !wfull;

    assign waddr = wptr[3:0];
    assign raddr = rptr[3:0];

    assign rdata = rdata_wire;
endmodule
